#pragma once
#define BATTERIES_BIT_OPS_BIT_COUNT_HPP

#include <batteries/config.hpp>
//
#include <batteries/int_types.hpp>
#include <batteries/utility.hpp>

#if BATT_CPP_20
#include <bit>
#endif  // BATT_CPP_20

namespace batt {

// 'SWAR' == SIMD Within A Register
//
namespace swar_bit_ops {

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
// From https://nimrod.blog/posts/algorithms-behind-popcount/
//
BATT_ALWAYS_INLINE constexpr i32 bit_count(u64 n)
{
    n = n - ((n >> 1) & 0x5555555555555555ull);
    n = (n & 0x3333333333333333ull) + ((n >> 2) & 0x3333333333333333ull);
    n = (n + (n >> 4)) & 0xF0F0F0F0F0F0F0Full;
    return (n * 0x101010101010101ull) >> 56;
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
// The bits that change when incrementing from n-1 to n are the zero bits plus one after.
//
BATT_ALWAYS_INLINE constexpr i32 trailing_zero_bits(u64 n)
{
    return n ? bit_count((n ^ (n - 1)) >> 1) : 64;
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
// Remove all non-leading zero bits, then flip and count.
//
BATT_ALWAYS_INLINE constexpr i32 leading_zero_bits(u64 n)
{
    n = n | (n >> 1);
    n = n | (n >> 2);
    n = n | (n >> 4);
    n = n | (n >> 8);
    n = n | (n >> 16);
    n = n | (n >> 32);

    return bit_count(~n);
}

}  // namespace swar_bit_ops

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
#if BATT_COMPILER_IS_GCC || BATT_COMPILER_IS_CLANG
BATT_ALWAYS_INLINE constexpr i32 bit_count(u64 n)
{
    return __builtin_popcountll(n);
}

//----- --- -- -  -  -   -
#elif BATT_CPP_20
BATT_ALWAYS_INLINE constexpr i32 bit_count(u64 n)
{
    return std::popcount<u64>(n);
}

//----- --- -- -  -  -   -
#else
using swar_bit_ops::bit_count;
#endif

//----- --- -- -  -  -   -
template <usize N>
BATT_ALWAYS_INLINE constexpr i32 bit_count(const std::array<u64, N>& bit_set)
{
    i32 total_count = 0;
    for (usize i = 0; i < N; ++i) {
        total_count += bit_count(bit_set[i]);
    }

    return total_count;
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
#if BATT_COMPILER_IS_GCC || BATT_COMPILER_IS_CLANG
BATT_ALWAYS_INLINE constexpr i32 trailing_zero_bits(u64 n)
{
    return n ? __builtin_ctzll(n) : 64;
}

//----- --- -- -  -  -   -
#elif BATT_CPP_20
BATT_ALWAYS_INLINE constexpr i32 trailing_zero_bits(u64 n)
{
    return std::countr_zero<u64>(n);
}

//----- --- -- -  -  -   -
#else
using swar_bit_ops::trailing_zero_bits;
#endif

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
#if BATT_COMPILER_IS_GCC || BATT_COMPILER_IS_CLANG
BATT_ALWAYS_INLINE constexpr i32 leading_zero_bits(u64 n)
{
    return n ? __builtin_clzll(n) : 64;
}

//----- --- -- -  -  -   -
#elif BATT_CPP_20
BATT_ALWAYS_INLINE constexpr i32 leading_zero_bits(u64 n)
{
    return std::countl_zero<u64>(n);
}

//----- --- -- -  -  -   -
#else
using swar_bit_ops::leading_zero_bits;
#endif

}  //namespace batt
